export const QUARTER_WORDS: Set<string> = new Set(['quarter', 'qtr', 'qrt', 'q']);

export const UNKNOWN_PHRASES: Set<string> = new Set([
  'unknown', 'date unknown', 'unk', 'unknow', 'not known',
  'unbekannt', 'unbek.', 'onbekend', 'inconnue',
]);

export const SPECIAL_PHRASES: Map<string, string> = new Map([
  ['in infancy', '(in infancy)'],
  ['died in infancy', '(in infancy)'],
  ['infant', '(in infancy)'],
  ['infancy', '(in infancy)'],
  ['young', '(young)'],
  ['died young', '(young)'],
  ['stillborn', '(stillborn)'],
]);

export const ORDINAL_SUFFIXES: Set<string> = new Set(['st', 'nd', 'rd', 'th']);

export const BC_WORDS: Set<string> = new Set(['bc', 'bce']);

export const AD_WORDS: Set<string> = new Set(['ad', 'ac', 'ce']);

export const WFT_PATTERN: RegExp = /wft/i;

/**
 * Helper functions for analyzing standardized genealogical dates.
 * These functions parse only the output of stdDate(), not raw date strings.
 */

import { MONTH_NUM, DAYS_IN_MONTH as RAW_DAYS_IN_MONTH } from "./date-constants.js";

// Adjusted for a true 365-day year (Feb = 28, not 29)
const DAYS_IN_MONTH = [...RAW_DAYS_IN_MONTH];
DAYS_IN_MONTH[2] = 28;

// Recalculate offsets with Feb=28 for a consistent 365-day year
const MONTH_DAY_OFFSETS = [0, 0, 31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334];

// Fudge factors: [earliestYearOffset, latestYearOffset, minDayOffset, maxDayOffset]
const FUDGE: Record<string, [number, number, number, number]> = {
  Abt: [-1, 1, -365, 365],
  Cal: [0, 0, 0, 0],
  Est: [-10, 10, -3650, 3650],
  Bef: [-10, 0, -3650, 0],
  Aft: [0, 10, 0, 3650],
};

const MONTH_ABBRS = 'Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec';

// Quarter start/end months
const QUARTER_START: Record<number, number> = { 1: 1, 2: 4, 3: 7, 4: 10 };
const QUARTER_END: Record<number, number> = { 1: 3, 2: 6, 3: 9, 4: 12 };

interface ParsedDate {
  modifier: string | null;
  day: number | null;
  month: number | null;  // 1-12
  year: number;
  quarter: number | null; // 1-4
}

/**
 * Strip trailing parenthetical text and uncertainty markers.
 */
function cleanInput(std: string): string {
  // Strip trailing (?), (SOME TEXT), and standalone ?
  let s = std.replace(/\s*\([^)]*\)\s*$/, '').trim();
  s = s.replace(/\s*\?\s*$/, '').trim();
  return s;
}

/**
 * Parse a single standardized date component (not a range or "or").
 * Returns null if no year can be extracted.
 */
function parseSingle(s: string): ParsedDate | null {
  s = s.trim();
  if (!s) return null;

  let modifier: string | null = null;
  let day: number | null = null;
  let month: number | null = null;
  let year: number | null = null;
  let quarter: number | null = null;

  // Check for modifier
  const modMatch = s.match(/^(Abt|Cal|Est|Bef|Aft)\s+/);
  if (modMatch) {
    modifier = modMatch[1];
    s = s.slice(modMatch[0].length);
  }

  // Check for quarter
  const qMatch = s.match(/^Q([1-4])\s+(\d+)$/);
  if (qMatch) {
    quarter = parseInt(qMatch[1]);
    year = parseInt(qMatch[2]);
    return { modifier, day, month, year, quarter };
  }

  // Check for BC
  let bc = false;
  if (s.match(/\s+BC$/)) {
    bc = true;
    s = s.replace(/\s+BC$/, '');
  }

  // Check for split year (e.g., 1623/24)
  const splitMatch = s.match(/(\d+)\/(\d{1,2})$/);
  if (splitMatch) {
    const baseYear = parseInt(splitMatch[1]);
    // Effective year for a split year is always baseYear + 1
    year = baseYear + 1;
    // Remove the split year part and parse rest
    s = s.replace(/\d+\/\d{1,2}$/, '').trim();
  }

  // Parse: optional day, optional month, year
  // Patterns: "28 Sep 1974", "Sep 1974", "1974", "28 Sep" (year already extracted from split)
  const fullMatch = s.match(new RegExp(`^(\\d{1,2})\\s+(${MONTH_ABBRS})(?:\\s+(\\d+))?$`));
  if (fullMatch) {
    day = parseInt(fullMatch[1]);
    month = MONTH_NUM.get(fullMatch[2])!;
    if (fullMatch[3] && year === null) year = parseInt(fullMatch[3]);
  } else {
    const monthYearMatch = s.match(new RegExp(`^(${MONTH_ABBRS})(?:\\s+(\\d+))?$`));
    if (monthYearMatch) {
      month = MONTH_NUM.get(monthYearMatch[1])!;
      if (monthYearMatch[2] && year === null) year = parseInt(monthYearMatch[2]);
    } else {
      const yearOnlyMatch = s.match(/^(\d+)$/);
      if (yearOnlyMatch && year === null) {
        year = parseInt(yearOnlyMatch[1]);
      }
    }
  }

  if (year === null) return null;
  if (bc) year = -year;

  return { modifier, day, month, year, quarter };
}

function getEarliestYear(p: ParsedDate): number {
  const fudge = p.modifier ? FUDGE[p.modifier] : null;
  const offset = fudge ? fudge[0] : 0;
  return p.year + offset;
}

function getLatestYear(p: ParsedDate): number {
  const fudge = p.modifier ? FUDGE[p.modifier] : null;
  const offset = fudge ? fudge[1] : 0;
  return p.year + offset;
}

/** True when the parsed date is missing day or month (i.e., not full DMY). */
function isImperfect(p: ParsedDate): boolean {
  if (p.quarter !== null) return true;
  return p.day === null || p.month === null;
}

/**
 * Calculate the minimum day number for a parsed date.
 *
 * When `imperfectDateFudgeDays > 0` and the date is imperfect (not full
 * day-month-year), the result is widened by an extra fudge to the early
 * side. Mirrors Java MobWarnings.getDateRange's imperfectDateFudgeDays
 * parameter (warnings.java:1564).
 */
function minDayNum(p: ParsedDate, imperfectDateFudgeDays = 0): number {
  const fudge = p.modifier ? FUDGE[p.modifier] : null;
  const dayOffset = fudge ? fudge[2] : 0;

  let minMonth: number;
  let minDay: number;

  if (p.quarter !== null) {
    minMonth = QUARTER_START[p.quarter];
    minDay = 1;
  } else {
    minMonth = p.month ?? 1;
    minDay = p.day ?? 1;
  }

  const imperfectOffset =
    imperfectDateFudgeDays > 0 && isImperfect(p)
      ? -imperfectDateFudgeDays
      : 0;

  return (
    p.year * 365 +
    MONTH_DAY_OFFSETS[minMonth] +
    minDay +
    dayOffset +
    imperfectOffset
  );
}

/**
 * Calculate the maximum day number for a parsed date.
 *
 * When `imperfectDateFudgeDays > 0` and the date is imperfect, the result
 * is widened by an extra fudge to the late side.
 */
function maxDayNum(p: ParsedDate, imperfectDateFudgeDays = 0): number {
  const fudge = p.modifier ? FUDGE[p.modifier] : null;
  const dayOffset = fudge ? fudge[3] : 0;

  let maxMonth: number;
  let maxDay: number;

  if (p.quarter !== null) {
    maxMonth = QUARTER_END[p.quarter];
    maxDay = DAYS_IN_MONTH[maxMonth];
  } else {
    maxMonth = p.month ?? 12;
    maxDay = p.day ?? DAYS_IN_MONTH[maxMonth];
  }

  const imperfectOffset =
    imperfectDateFudgeDays > 0 && isImperfect(p)
      ? imperfectDateFudgeDays
      : 0;

  return (
    p.year * 365 +
    MONTH_DAY_OFFSETS[maxMonth] +
    maxDay +
    dayOffset +
    imperfectOffset
  );
}

interface DateRange {
  min: number;
  max: number;
}

/**
 * Get the full day range [min, max] for a standardized date string.
 * Returns null if no year can be extracted.
 *
 * When `imperfectDateFudgeDays > 0`, the range is widened by an extra
 * fudge for date components that aren't full day-month-year. Mirrors
 * Java MobWarnings.getDateRange's imperfectDateFudgeDays parameter
 * (warnings.java:1564) — checks like hasChristeningBeforeBirth pass 365
 * here so that "Christening 1850" vs "Birth 1851" doesn't naively fire.
 */
export function getDayRange(
  std: string,
  imperfectDateFudgeDays = 0,
): DateRange | null {
  const cleaned = cleanInput(std);
  if (!cleaned) return null;

  // Check for range: "Bet X and Y"
  const rangeMatch = cleaned.match(/^Bet\s+(.+?)\s+and\s+(.+)$/);
  if (rangeMatch) {
    const start = parseSingle(rangeMatch[1]);
    const end = parseSingle(rangeMatch[2]);
    if (!start || !end) return null;
    return {
      min: minDayNum(start, imperfectDateFudgeDays),
      max: maxDayNum(end, imperfectDateFudgeDays),
    };
  }

  // Check for "or": "X or Y"
  const orMatch = cleaned.match(/^(.+?)\s+or\s+(.+)$/);
  if (orMatch) {
    const a = parseSingle(orMatch[1]);
    const b = parseSingle(orMatch[2]);
    if (!a || !b) return null;
    return {
      min: Math.min(
        minDayNum(a, imperfectDateFudgeDays),
        minDayNum(b, imperfectDateFudgeDays),
      ),
      max: Math.max(
        maxDayNum(a, imperfectDateFudgeDays),
        maxDayNum(b, imperfectDateFudgeDays),
      ),
    };
  }

  // Single date
  const p = parseSingle(cleaned);
  if (!p) return null;
  return {
    min: minDayNum(p, imperfectDateFudgeDays),
    max: maxDayNum(p, imperfectDateFudgeDays),
  };
}

/**
 * Returns the earliest possible year for a standardized date string.
 */
export function earliestYear(std: string): number | null {
  const cleaned = cleanInput(std);
  if (!cleaned) return null;

  // Check for range: "Bet X and Y" — use start
  const rangeMatch = cleaned.match(/^Bet\s+(.+?)\s+and\s+(.+)$/);
  if (rangeMatch) {
    const start = parseSingle(rangeMatch[1]);
    if (!start) return null;
    return getEarliestYear(start);
  }

  // Check for "or": minimum earliest
  const orMatch = cleaned.match(/^(.+?)\s+or\s+(.+)$/);
  if (orMatch) {
    const a = parseSingle(orMatch[1]);
    const b = parseSingle(orMatch[2]);
    if (!a || !b) return null;
    return Math.min(getEarliestYear(a), getEarliestYear(b));
  }

  const p = parseSingle(cleaned);
  if (!p) return null;
  return getEarliestYear(p);
}

/**
 * Returns the latest possible year for a standardized date string.
 */
export function latestYear(std: string): number | null {
  const cleaned = cleanInput(std);
  if (!cleaned) return null;

  // Check for range: "Bet X and Y" — use end
  const rangeMatch = cleaned.match(/^Bet\s+(.+?)\s+and\s+(.+)$/);
  if (rangeMatch) {
    const end = parseSingle(rangeMatch[2]);
    if (!end) return null;
    return getLatestYear(end);
  }

  // Check for "or": maximum latest
  const orMatch = cleaned.match(/^(.+?)\s+or\s+(.+)$/);
  if (orMatch) {
    const a = parseSingle(orMatch[1]);
    const b = parseSingle(orMatch[2]);
    if (!a || !b) return null;
    return Math.max(getLatestYear(a), getLatestYear(b));
  }

  const p = parseSingle(cleaned);
  if (!p) return null;
  return getLatestYear(p);
}

/**
 * Returns the smallest possible gap in days between two standardized dates.
 * Returns 0 if the ranges overlap.
 * Returns null if either date has no year.
 */
export function minDaysDiff(std1: string, std2: string): number | null {
  const r1 = getDayRange(std1);
  const r2 = getDayRange(std2);
  if (!r1 || !r2) return null;

  // Check if ranges overlap
  if (r1.max >= r2.min && r2.max >= r1.min) return 0;

  // Return distance between closest edges
  if (r1.max < r2.min) return r2.min - r1.max;
  return r1.min - r2.max;
}

/**
 * Returns the largest possible gap in days between two standardized dates.
 * Returns null if either date has no year.
 */
export function maxDaysDiff(std1: string, std2: string): number | null {
  const r1 = getDayRange(std1);
  const r2 = getDayRange(std2);
  if (!r1 || !r2) return null;

  // Return distance between farthest edges
  return Math.max(
    Math.abs(r2.max - r1.min),
    Math.abs(r1.max - r2.min),
  );
}

/**
 * Returns true if std1 is definitely before std2 at day-level precision —
 * std1's latest possible day is earlier than std2's earliest possible day.
 *
 * Returns false if std1 is definitely on-or-after std2.
 * Returns null when the day-level ranges overlap (cannot say which is earlier)
 *   or when either date is unparseable.
 */
export function isABeforeB(std1: string, std2: string): boolean | null {
  const r1 = getDayRange(std1);
  const r2 = getDayRange(std2);
  if (!r1 || !r2) return null;

  if (r1.max < r2.min) return true;
  if (r1.min > r2.max) return false;
  return null;
}

/**
 * Genealogical date standardizer.
 * Converts free-form date strings into a canonical format.
 */
import {
  normalizeAccents,
  MONTHS,
  MONTH_NUM,
  MODIFIERS,
  QUARTER_WORDS,
  UNKNOWN_PHRASES,
  SPECIAL_PHRASES,
  ORDINAL_SUFFIXES,
  BC_WORDS,
  AD_WORDS,
  WFT_PATTERN,
} from "./date-constants.js";

// ---------- Token types ----------
interface Token {
  type: 'num' | 'str' | 'sym';
  value: string;
}

// ---------- Parsed date components ----------
interface DateParts {
  modifier?: string;
  day?: number;
  month?: string;       // 3-letter abbreviation
  year?: number;
  splitYear?: string;   // e.g. "24", "00"
  bc?: boolean;
  uncertain?: boolean;
  quarter?: number;     // 1-4 for quarter dates
}

// ---------- Tokenizer ----------
function tokenize(s: string): Token[] {
  const tokens: Token[] = [];
  let i = 0;
  while (i < s.length) {
    const ch = s[i];
    if (/[0-9]/.test(ch)) {
      let num = '';
      while (i < s.length && /[0-9]/.test(s[i])) num += s[i++];
      tokens.push({ type: 'num', value: num });
    } else if (/[a-zA-Z]/.test(ch)) {
      let str = '';
      while (i < s.length && /[a-zA-Z]/.test(s[i])) str += s[i++];
      tokens.push({ type: 'str', value: str });
    } else if (ch === '/' || ch === '<' || ch === '>' || ch === '&') {
      tokens.push({ type: 'sym', value: ch });
      i++;
    } else {
      i++;
    }
  }
  return tokens;
}

// ---------- Format a single date ----------
function formatDate(d: DateParts): string {
  const parts: string[] = [];
  if (d.modifier) parts.push(d.modifier);
  if (d.day !== undefined) parts.push(String(d.day));
  if (d.month) parts.push(d.month);
  if (d.year !== undefined) {
    let yearStr = String(d.year);
    if (d.splitYear !== undefined) yearStr += '/' + d.splitYear;
    parts.push(yearStr);
  }
  if (d.bc) parts.push('BC');
  if (d.uncertain) parts.push('(?)');
  return parts.join(' ');
}

// ---------- Number-to-month ----------
function numToMonth(n: number): string | undefined {
  for (const [abbr, num] of MONTH_NUM) {
    if (num === n) return abbr;
  }
  return undefined;
}

// ---------- Pre-processing ----------
function preProcess(raw: string): { text: string; trailingParen: string; uncertain: boolean; orDates: string[] | null } {
  let text = raw;
  let trailingParen = '';
  let uncertain = false;
  const orDates: string[] | null = null;

  // Convert em-dashes/en-dashes to hyphens
  text = text.replace(/[\u2013\u2014]/g, '-');

  // Replace b.c. with bc (but not at start where it might mean "before circa")
  text = text.replace(/(?!^)b\.c\./gi, 'bc');

  // Extract trailing parenthetical
  const parenMatch = text.match(/^(.*?)\s*(\([^)]*\))\s*$/);
  if (parenMatch && parenMatch[1].trim().length > 0) {
    text = parenMatch[1].trim();
    trailingParen = parenMatch[2];
  }

  // Handle question mark
  if (text.includes('?')) {
    uncertain = true;
    text = text.replace(/\?/g, '');
  }

  // Detect YYYYMMDD (exactly 8 digits, standalone)
  const yyyymmddMatch = text.match(/^(\d{8})$/);
  if (yyyymmddMatch) {
    const digits = yyyymmddMatch[1];
    const y = parseInt(digits.substring(0, 4), 10);
    const m = parseInt(digits.substring(4, 6), 10);
    const d = parseInt(digits.substring(6, 8), 10);
    if (y >= 1000 && y <= 2200 && m >= 1 && m <= 12 && d >= 1 && d <= 31) {
      const mon = numToMonth(m);
      if (mon) {
        text = `${d} ${mon} ${y}`;
      }
    }
  }

  // Convert yyyy-mm-dd / yyyy/mm/dd / yyyy.mm.dd embedded dates
  text = text.replace(/(\d{4})[/.\-](\d{1,2})[/.\-](\d{1,2})/g, (_match, y, m, d) => {
    const yy = parseInt(y, 10);
    const mm = parseInt(m, 10);
    const dd = parseInt(d, 10);
    if (yy >= 1000 && yy <= 2200 && mm >= 1 && mm <= 12 && dd >= 1 && dd <= 31) {
      const mon = numToMonth(mm);
      if (mon) return `${dd} ${mon} ${yy}`;
    }
    return _match;
  });

  // Handle ambiguous mm-dd-yyyy / dd-mm-yyyy
  text = text.replace(/(\d{1,2})[/.\-](\d{1,2})[/.\-](\d{4})/g, (_match, a, b, y) => {
    const aa = parseInt(a, 10);
    const bb = parseInt(b, 10);
    const yy = parseInt(y, 10);
    if (yy < 1000 || yy > 2200) return _match;

    const aIsDay = aa >= 1 && aa <= 31;
    const bIsDay = bb >= 1 && bb <= 31;
    const aIsMonth = aa >= 1 && aa <= 12;
    const bIsMonth = bb >= 1 && bb <= 12;

    if (aa > 12 && bIsMonth) {
      // dd-mm-yyyy
      const mon = numToMonth(bb);
      return mon ? `${aa} ${mon} ${yy}` : _match;
    } else if (bb > 12 && aIsMonth) {
      // mm-dd-yyyy
      const mon = numToMonth(aa);
      return mon ? `${bb} ${mon} ${yy}` : _match;
    } else if (aIsMonth && bIsDay && aa === bb) {
      // Same number, pick mm-dd-yyyy interpretation
      const mon = numToMonth(aa);
      return mon ? `${bb} ${mon} ${yy}` : _match;
    } else if (aIsMonth && bIsMonth && aIsDay && bIsDay && aa !== bb) {
      // Truly ambiguous
      const monA = numToMonth(aa);
      const monB = numToMonth(bb);
      if (monA && monB) {
        return `__OR__${bb} ${monA} ${yy}__OR__${aa} ${monB} ${yy}__OR__`;
      }
      return _match;
    }
    return _match;
  });

  // Convert dd-Mon-yyyy (dashes between day/month/year with alpha month) → spaces
  text = text.replace(/(\d{1,2})-([a-zA-Z]+)-(\d{4})/g, '$1 $2 $3');

  // Handle abbreviated year ranges: 1875-80 → 1875-1880 (BEFORE dash processing)
  text = text.replace(/(\d{4})-(\d{1,3})(?!\d)/g, (_match, base, suffix) => {
    const baseYear = parseInt(base, 10);
    const suffixNum = parseInt(suffix, 10);
    if (baseYear >= 1000 && baseYear <= 2200 && suffix.length < 4) {
      // Check it's not already a full year range converted above
      const suffixLen = suffix.length;
      const expanded = Math.floor(baseYear / Math.pow(10, suffixLen)) * Math.pow(10, suffixLen) + suffixNum;
      return `${base}-${expanded}`;
    }
    return _match;
  });

  // Handle dashes as range separators
  if (text.includes('-')) {
    const lowerText = text.toLowerCase();
    const hasBet = /\b(bet|btw|between)\b/.test(lowerText);
    const hasFrom = /\b(from|frm)\b/.test(lowerText);

    if (hasBet) {
      text = text.replace(/-/g, ' and ');
    } else if (hasFrom) {
      text = text.replace(/-/g, ' to ');
    } else {
      // Check if there's a dash that looks like a range separator (between date-like content)
      // Only convert dashes that are surrounded by spaces or date-like content
      text = 'from ' + text.replace(/-/g, ' to ');
    }
  }

  return { text: text.trim(), trailingParen, uncertain, orDates };
}

// ---------- Main parser ----------
function parseDateTokens(tokens: Token[], startIdx: number, endIdx: number): DateParts {
  const parts: DateParts = {};
  const pendingNums: number[] = [];
  let i = startIdx;

  while (i < endIdx) {
    const tok = tokens[i];

    if (tok.type === 'str') {
      const lower = normalizeAccents(tok.value).toLowerCase();

      // Check for month
      const monthAbbr = MONTHS.get(lower);
      if (monthAbbr) {
        parts.month = monthAbbr;
        // If we had a pending number <= 31, it's a day
        if (pendingNums.length === 1 && pendingNums[0] <= 31) {
          parts.day = pendingNums[0];
          pendingNums.length = 0;
        }
        i++;
        continue;
      }

      // Check for ordinal suffix after number
      if (ORDINAL_SUFFIXES.has(lower) && pendingNums.length > 0) {
        // Just ignore the suffix; the number is already stored
        i++;
        continue;
      }

      // Check for quarter word
      if (QUARTER_WORDS.has(lower)) {
        i++;
        continue;
      }

      // Check for BC
      if (BC_WORDS.has(lower)) {
        parts.bc = true;
        i++;
        continue;
      }

      // Check for AD
      if (AD_WORDS.has(lower)) {
        // Just discard
        i++;
        continue;
      }

      // Check for modifier
      const mod = MODIFIERS.get(lower);
      if (mod) {
        if (mod === 'and' || mod === 'or' || mod === 'From' || mod === 'To' || mod === 'Bet') {
          // These are handled at a higher level
          i++;
          continue;
        }
        if (parts.modifier) {
          // Double modifier — keep the first (primary)
          i++;
          continue;
        }
        parts.modifier = mod;
        i++;
        continue;
      }

      // Unknown string — skip
      i++;
      continue;
    }

    if (tok.type === 'num') {
      const num = parseInt(tok.value, 10);

      // Check if next token is an ordinal suffix
      if (i + 1 < endIdx && tokens[i + 1].type === 'str') {
        const nextLower = tokens[i + 1].value.toLowerCase();
        if (ORDINAL_SUFFIXES.has(nextLower)) {
          // Check if the token after ordinal is a quarter word
          if (i + 2 < endIdx && tokens[i + 2].type === 'str') {
            const qLower = tokens[i + 2].value.toLowerCase();
            if (QUARTER_WORDS.has(qLower) && num >= 1 && num <= 4) {
              // This is a quarter: "1st quarter"
              parts.day = undefined;
              parts.month = undefined;
              // Store quarter in a special way — we'll use day field as quarter marker
              pendingNums.push(num);
              // Mark this as quarter
              parts.quarter = num;
              i += 3; // skip num, ordinal, quarter word
              continue;
            }
          }
        }
      }

      // Check if next token is a quarter word directly (e.g., "1 quarter")
      if (i + 1 < endIdx && tokens[i + 1].type === 'str') {
        const nextLower = tokens[i + 1].value.toLowerCase();
        if (QUARTER_WORDS.has(nextLower) && num >= 1 && num <= 4) {
          parts.quarter = num;
          i += 2;
          continue;
        }
      }

      if (num >= 1000 && num <= 2200) {
        parts.year = num;
        // If there's a pending number and it could be a day
        if (pendingNums.length === 1 && pendingNums[0] >= 1 && pendingNums[0] <= 31) {
          parts.day = pendingNums[0];
        }
        pendingNums.length = 0;
        i++;

        // Check for split year: / followed by number
        if (i < endIdx && tokens[i].type === 'sym' && tokens[i].value === '/' &&
            i + 1 < endIdx && tokens[i + 1].type === 'num') {
          const suffixTok = tokens[i + 1];
          const suffixVal = parseInt(suffixTok.value, 10);

          if (num >= 1000 && num <= 1752) {
            // Valid split year range
            const nextYear = num + 1;
            const suffixLen = suffixTok.value.length;

            if (suffixLen <= 2) {
              // Verify suffix matches nextYear
              if (suffixLen === 1) {
                if ((nextYear % 10) === suffixVal) {
                  parts.splitYear = String(nextYear % 100).padStart(2, '0');
                  i += 2;
                } else {
                  // Invalid split year
                  parts.splitYear = undefined;
                }
              } else {
                if ((nextYear % 100) === suffixVal) {
                  parts.splitYear = suffixTok.value.padStart(2, '0');
                  i += 2;
                } else {
                  parts.splitYear = undefined;
                }
              }
            } else if (suffixLen === 3 || suffixLen === 4) {
              // e.g. 1699/1700
              if (suffixVal === nextYear) {
                parts.splitYear = String(nextYear % 100).padStart(2, '0');
                i += 2;
              }
            }

            // Check month validity for split years (only Jan-Mar)
            if (parts.splitYear !== undefined && parts.month) {
              const monthNum = MONTH_NUM.get(parts.month);
              if (monthNum && monthNum > 3) {
                parts.uncertain = true;
              }
            }
          } else {
            // Year > 1752, not valid split year — don't consume / and next num
            // Leave them for other processing
          }
        }
        continue;
      }

      // It's a smaller number
      if (parts.month && !parts.day && num >= 1 && num <= 31) {
        parts.day = num;
        i++;
        continue;
      }

      // Could be a day or a two-digit year (BC context)
      pendingNums.push(num);
      i++;
      continue;
    }

    if (tok.type === 'sym') {
      if (tok.value === '<' || tok.value === '>') {
        const mod = MODIFIERS.get(tok.value);
        if (mod && !parts.modifier) {
          parts.modifier = mod;
        }
      }
      i++;
      continue;
    }

    i++;
  }

  // Resolve pending numbers
  if (pendingNums.length > 0) {
    for (const num of pendingNums) {
      if (num >= 1000 && num <= 2200) {
        if (!parts.year) parts.year = num;
      } else if (parts.bc && num < 100) {
        if (!parts.year) parts.year = num;
      } else if (num >= 1 && num <= 31 && !parts.day) {
        // Store as potential day even without month (for range gap filling)
        parts.day = num;
      } else if (parts.quarter && num >= 1000 && num <= 2200) {
        parts.year = num;
      }
    }
  }

  return parts;
}

// Find all positions of a modifier keyword (checks both str and sym tokens)
function findAllModifier(tokens: Token[], keyword: string): number[] {
  const positions: number[] = [];
  for (let i = 0; i < tokens.length; i++) {
    const tok = tokens[i];
    let lookup: string | undefined;
    if (tok.type === 'str') {
      lookup = MODIFIERS.get(tok.value.toLowerCase());
    } else if (tok.type === 'sym') {
      lookup = MODIFIERS.get(tok.value);
    }
    if (lookup === keyword) positions.push(i);
  }
  return positions;
}

// ---------- Main export ----------
export function stdDate(raw: string): string {
  // 1. Empty/whitespace
  if (!raw || !raw.trim()) return '';

  const trimmed = raw.trim();
  const lowerTrimmed = trimmed.toLowerCase();

  // 2. Unknown phrases
  if (UNKNOWN_PHRASES.has(lowerTrimmed)) return '';

  // 3. Special phrases (check before other processing)
  const specialResult = SPECIAL_PHRASES.get(lowerTrimmed);
  if (specialResult) {
    return specialResult;
  }

  // Also check with trailing parenthetical stripped
  const specialParenMatch = trimmed.match(/^(.*?)\s*(\([^)]*\))\s*$/);
  if (specialParenMatch) {
    const base = specialParenMatch[1].trim().toLowerCase();
    const paren = specialParenMatch[2];
    const sp = SPECIAL_PHRASES.get(base);
    if (sp) return sp + ' ' + paren;
  }

  // 4. WFT patterns
  if (WFT_PATTERN.test(trimmed)) return '';

  // Handle input that is entirely parenthetical
  if (/^\([^)]*\)$/.test(trimmed)) {
    return trimmed;
  }

  // 5. Pre-process
  const { text, trailingParen, uncertain } = preProcess(trimmed);

  if (!text) return '';

  // Check for __OR__ pattern (ambiguous date)
  if (text.includes('__OR__')) {
    const orParts = text.match(/__OR__(.*?)__OR__(.*?)__OR__/);
    if (orParts) {
      const interp1 = orParts[1].trim();
      const interp2 = orParts[2].trim();

      // Parse each interpretation (they may have prefixes from pre-processing)
      let result = `${interp1} or ${interp2}`;
      if (trailingParen) result += ' ' + trailingParen;
      if (uncertain) result += ' (?)';
      return result;
    }
  }

  // Tokenize
  const allTokens = tokenize(normalizeAccents(text));

  if (allTokens.length === 0) return '';

  // Check for "Q" prefix for quarters (e.g., "Q1")
  if (allTokens.length >= 2 && allTokens[0].type === 'str' &&
      allTokens[0].value.toLowerCase() === 'q' && allTokens[1].type === 'num') {
    const qNum = parseInt(allTokens[1].value, 10);
    if (qNum >= 1 && qNum <= 4 && allTokens.length >= 3) {
      const yearTok = allTokens[2];
      if (yearTok.type === 'num') {
        const year = parseInt(yearTok.value, 10);
        if (year >= 1000 && year <= 2200) {
          let result = `Q${qNum} ${year}`;
          if (trailingParen) result += ' ' + trailingParen;
          return result;
        }
      }
    }
  }

  // Check for From/To pattern
  const fromPositions = findAllModifier(allTokens, 'From');
  const toPositions = findAllModifier(allTokens, 'To');
  const betPositions = findAllModifier(allTokens, 'Bet');
  const andPositions = findAllModifier(allTokens, 'and');

  // Check for Bet...and range
  if (betPositions.length > 0 && andPositions.length > 0) {
    const betIdx = betPositions[0];
    const andIdx = andPositions[0];
    if (andIdx > betIdx) {
      const date1 = parseDateTokens(allTokens, betIdx + 1, andIdx);
      const date2 = parseDateTokens(allTokens, andIdx + 1, allTokens.length);

      // Range gap filling
      fillRangeGaps(date1, date2);

      const d1str = formatDate(date1);
      const d2str = formatDate(date2);
      if (!date1.year && !date2.year) return '';
      let result = `Bet ${d1str} and ${d2str}`;
      if (trailingParen) result += ' ' + trailingParen;
      if (uncertain) result += ' (?)';
      return result;
    }
  }

  // Check for From...To range
  if (fromPositions.length > 0 && toPositions.length > 0) {
    const fromIdx = fromPositions[0];
    const toIdx = toPositions[0];
    if (toIdx > fromIdx) {
      const date1 = parseDateTokens(allTokens, fromIdx + 1, toIdx);
      const date2 = parseDateTokens(allTokens, toIdx + 1, allTokens.length);

      fillRangeGaps(date1, date2);

      const d1str = formatDate(date1);
      const d2str = formatDate(date2);
      if (!date1.year && !date2.year) return '';
      let result = `Bet ${d1str} and ${d2str}`;
      if (trailingParen) result += ' ' + trailingParen;
      if (uncertain) result += ' (?)';
      return result;
    }
  }

  // Standalone From → Aft
  if (fromPositions.length > 0 && toPositions.length === 0 && andPositions.length === 0) {
    const fromIdx = fromPositions[0];
    const date = parseDateTokens(allTokens, fromIdx + 1, allTokens.length);
    if (!date.year) return '';
    date.modifier = 'Aft';
    let result = formatDate(date);
    if (trailingParen) result += ' ' + trailingParen;
    if (uncertain) result += ' (?)';
    return result;
  }

  // Standalone To → Bef
  if (toPositions.length > 0 && fromPositions.length === 0) {
    const toIdx = toPositions[0];
    const date = parseDateTokens(allTokens, toIdx + 1, allTokens.length);
    if (!date.year) return '';
    date.modifier = 'Bef';
    let result = formatDate(date);
    if (trailingParen) result += ' ' + trailingParen;
    if (uncertain) result += ' (?)';
    return result;
  }

  // Single date parse
  const date = parseDateTokens(allTokens, 0, allTokens.length);

  // Check for quarter
  if (date.quarter) {
    const q = date.quarter;
    if (date.year) {
      let result = `Q${q} ${date.year}`;
      if (trailingParen) result += ' ' + trailingParen;
      return result;
    }
  }

  // Validate
  if (!date.year && !date.month && !date.day) {
    // Check if there was only a modifier
    return '';
  }

  if (!date.year) {
    // No year found
    return '';
  }

  // Two-digit year without BC context
  if (date.year < 100 && !date.bc) {
    return '';
  }

  if (uncertain) date.uncertain = true;

  let result = formatDate(date);
  if (trailingParen) result += ' ' + trailingParen;
  return result;
}


// ---------- Range gap filling ----------
function fillRangeGaps(date1: DateParts, date2: DateParts): void {
  // If date1 missing year but date2 has year, copy year
  if (!date1.year && date2.year) {
    date1.year = date2.year;
  }
  // If date1 missing month but date2 has month and date1 has day, copy month
  if (!date1.month && date2.month && date1.day) {
    date1.month = date2.month;
  }
  // If date1 has a pending number (stored nowhere yet) but no day, and date1 has no month...
  // This is handled in the parser when a number is left in pendingNums
